"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[9128],{6248(e,o,t){t.r(o),t.d(o,{assets:()=>h,contentTitle:()=>r,default:()=>u,frontMatter:()=>a,metadata:()=>s,toc:()=>l});const s=JSON.parse('{"id":"stoicism/epictetus/discourses/book-3/discourses-book-3-chapter-2","title":"Discourses \u2014 Book 3, Chapter 2","description":"Book 3 \u2014 Chapter 2","source":"@site/docs/stoicism/epictetus/discourses/book-3/discourses-book-3-chapter-2.md","sourceDirName":"stoicism/epictetus/discourses/book-3","slug":"/stoicism/epictetus/discourses/book-3/discourses-book-3-chapter-2","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-3/discourses-book-3-chapter-2","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":2,"frontMatter":{"sidebar_position":2,"title":"Discourses \u2014 Book 3, Chapter 2","sidebar_label":"Book 3, Ch. 2"},"sidebar":"philosophersSidebar","previous":{"title":"Book 3, Ch. 1","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-3/discourses-book-3-chapter-1"},"next":{"title":"Book 3, Ch. 3","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-3/discourses-book-3-chapter-3"}}');var n=t(4848),i=t(8453);const a={sidebar_position:2,title:"Discourses \u2014 Book 3, Chapter 2",sidebar_label:"Book 3, Ch. 2"},r="Discourses",h={},l=[{value:"Book 3 \u2014 Chapter 2",id:"book-3--chapter-2",level:2},{value:"1) In What Matters Should The Man Who Is To Make Progress Train Himself: And (2) That We Neglect What Is Most Vital",id:"1-in-what-matters-should-the-man-who-is-to-make-progress-train-himself-and-2-that-we-neglect-what-is-most-vital",level:3},{value:"Text",id:"text",level:2}];function d(e){const o={em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",p:"p",...(0,i.R)(),...e.components},{Details:t}=o;return t||function(e,o){throw new Error("Expected "+(o?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Details",!0),(0,n.jsxs)(n.Fragment,{children:[(0,n.jsxs)("div",{style:{textAlign:"center"},children:[(0,n.jsx)(o.header,{children:(0,n.jsx)(o.h1,{id:"discourses",children:"Discourses"})}),(0,n.jsx)(o.h2,{id:"book-3--chapter-2",children:"Book 3 \u2014 Chapter 2"}),(0,n.jsx)(o.h3,{id:"1-in-what-matters-should-the-man-who-is-to-make-progress-train-himself-and-2-that-we-neglect-what-is-most-vital",children:"1) In What Matters Should The Man Who Is To Make Progress Train Himself: And (2) That We Neglect What Is Most Vital"})]}),"\n",(0,n.jsx)(o.p,{children:(0,n.jsx)(o.em,{children:"Translated by P.E. Matheson (Oxford: Clarendon Press, 1916)"})}),"\n",(0,n.jsxs)(t,{open:!0,children:[(0,n.jsx)("summary",{children:"Text"}),(0,n.jsx)(o.h2,{id:"text",children:"Text"}),(0,n.jsx)(o.p,{children:"THERE are three departments  in which a man who is to be good and noble must be trained. The first concerns the will to get and will to avoid; he must be trained not to fail to get what he wills to get nor fall into what he wills to avoid. The second is concerned with impulse to act and not to act, and, in a word, the sphere of what is fitting: that we should act in order, with due consideration, and with proper care. The object of the third is that we may not be deceived, and may not judge at random, and generally it is concerned with assent."}),(0,n.jsx)(o.p,{children:"Of these the most important and the most pressing is the first, which is concerned with strong emotions, for such emotion does not arise except when the will to get or the will to avoid fails of its object. This it is which brings with it disturbances, tumults, misfortunes, bad fortunes, mournings, lamentations, envies; which makes men envious and jealous--passions which make us unable to listen to reason."}),(0,n.jsx)(o.p,{children:"The second is the sphere of what is fitting: for I must not be without"}),(0,n.jsx)(o.p,{children:"feeling like a statue, but must maintain my natural and acquired relations, as a religious man, as son, brother, father, citizen."}),(0,n.jsx)(o.p,{children:"The third department is appropriate only for those who are already making progress, and is concerned with giving certainty in the very things we have spoken of, so that even in sleep or drunkenness or melancholy no untested impression may come upon us unawares."}),(0,n.jsx)(o.p,{children:"'This', says a pupil, 'is beyond us.'"}),(0,n.jsx)(o.p,{children:"But the philosophers of to-day have disregarded the first and second departments, and devote themselves to the third--variable premisses, syllogisms concluding with a question, hypothetical syllogisms, fallacious arguments."}),(0,n.jsx)(o.p,{children:"'Of course,' he says, 'when a man, is engaged on these subjects he must take pains to escape being deceived.' But whose business is it to do this? It is only for the man who is already good."}),(0,n.jsx)(o.p,{children:"In logic then you fall short: but have you reached perfection in other subjects? Are you proof against deceit in regard to money? If you see a pretty girl, do you resist the impression? If your neighbour comes in for an inheritance, do you not feel a twinge? Do you lack nothing now but security of judgement? Unhappy man, even while you are learning this lesson you are in an agony of terror lest some one should think scorn of you, and you ask whether any one is talking about you! And if some one comes and tells you, 'We were discussing who was the best philosopher, and one who was there said, \"There is only one philosopher, So-and-so (naming you)\"', straightway your poor little four-inch soul shoots up to two cubits! Then if another who is by says, 'Nonsense! It is not worth while to listen to So-and-so: what does he know? He has the first rudiments, nothing more', you are beside yourself, and grow pale and cry out at once, 'I will show him the man I am, he shall see I am a great philosopher.' Why, the facts themselves are evidence; why do you want to show it by something else? Do you not know that Diogenes pointed out one of the sophists thus, making a vulgar gesture? Then, when the man was furious, 'That is So-and-so,' said he, 'I have shown him to you.' A man is not indeed like a stone or a log, that you can show what he is by just pointing a finger, but you show what he is as a man, when you show what are his judgements."}),(0,n.jsx)(o.p,{children:"Let us look at your judgements too. Is it not clear that you set no value on your will, but look outside to things beyond your will?--what So-and-so will say, what men will think of you, whether they will think you a scholar, one who has read Chrysippus or Antipater, for if you have read them and Archedemus as well, you have read everything. Why are you still in agony, lest you should fail to show us what manner of man you are? Would you like me to say what manner of man you showed yourself to us? A man who comes before us mean, critical, quick-tempered,"}),(0,n.jsx)(o.p,{children:"cowardly, blaming everything, accusing every one, never quiet, vainglorious--that is what you showed us! Go away now and read Archedemus; then if a mouse fall and make a noise, you die of fright! For the same sort of death awaits you, as--whom shall I say?--Crinis! He too was proud of understanding Archedemus!"}),(0,n.jsx)(o.p,{children:"Unhappy man, will you not leave these things alone, which do not concern you? They are suited only to those who can learn them without confusion, to those who are able to say, 'I feel no anger, pain, or envy; I am under no hindrance, no constraint. What is left for me to do? I have leisure and peace of mind. Let us see how we ought to deal with logical changes: let us see how one may adopt a hypothesis and not be led to an absurd conclusion.'"}),(0,n.jsx)(o.p,{children:"These are matters well enough for men like that. It is fitting for sailors who are in good trim to light a fire, and take their dinner, if luck serves, and to sing and dance: but you come to me when the ship is sinking and begin hoisting the topsails!"})]})]})}function u(e={}){const{wrapper:o}={...(0,i.R)(),...e.components};return o?(0,n.jsx)(o,{...e,children:(0,n.jsx)(d,{...e})}):d(e)}},8453(e,o,t){t.d(o,{R:()=>a,x:()=>r});var s=t(6540);const n={},i=s.createContext(n);function a(e){const o=s.useContext(i);return s.useMemo(function(){return"function"==typeof e?e(o):{...o,...e}},[o,e])}function r(e){let o;return o=e.disableParentContext?"function"==typeof e.components?e.components(n):e.components||n:a(e.components),s.createElement(i.Provider,{value:o},e.children)}}}]);